575→```typescript
576→// backend/src/utils/encryption.util.ts
577→import { createCipheriv, createDecipheriv, randomBytes } from 'node:crypto';
578→
579→const ALGORITHM = 'aes-256-gcm';
580→const IV_LENGTH = 16;
581→const AUTH_TAG_LENGTH = 16;
582→
583→export function encrypt({ plaintext, key }: { plaintext: string; key: string }): string {
584→  const iv = randomBytes(IV_LENGTH);
585→  const cipher = createCipheriv(ALGORITHM, Buffer.from(key, 'hex'), iv);
586→  const encrypted = Buffer.concat([cipher.update(plaintext, 'utf8'), cipher.final()]);
587→  const authTag = cipher.getAuthTag();
588→  return Buffer.concat([iv, authTag, encrypted]).toString('base64url');
589→}
590→
591→export function decrypt({ ciphertext, key }: { ciphertext: string; key: string }): string {
592→  const data = Buffer.from(ciphertext, 'base64url');
593→  const iv = data.subarray(0, IV_LENGTH);
594→  const authTag = data.subarray(IV_LENGTH, IV_LENGTH + AUTH_TAG_LENGTH);
595→  const encrypted = data.subarray(IV_LENGTH + AUTH_TAG_LENGTH);
596→  const decipher = createDecipheriv(ALGORITHM, Buffer.from(key, 'hex'), iv);
597→  decipher.setAuthTag(authTag);
598→  return decipher.update(encrypted) + decipher.final('utf8');
599→}

